@theme {
  --color-primary: oklch(0.55 0.24 263);
  --color-primary-hover: oklch(0.48 0.24 263);
  --color-primary-foreground: oklch(0.98 0 0);
  --color-muted: oklch(0.9 0.05 263);
  --color-border: oklch(0.82 0.08 263);
  --color-ring: oklch(0.6 0.2 263);
  --color-surface: oklch(1 0 0);

  --radius-sm: 0.5rem;
  --radius-default: 9999px;
  --radius-lg: 9999px;
}
